"""
MKT Original Language Commentary — Proverbs chapters 22–24
Run: python3 scripts/zc-original-proverbs-22-24.py

Source data used:
- data/interlinear/proverbs.json
- data/translation/notes/proverbs.json
- data/translation/draft/mediating/proverbs.json (MKT text)

Key decisions:
- 22:17–24:22 = "Words of the Wise" (Thirty Sayings), a distinct super-collection
  with documented parallels to the Egyptian Instruction of Amenemope; literary-
  historical context noted where relevant but not over-pressed.
- נֶפֶשׁ (nephesh): "soul" when the referent is the appetite or inner person
  (22:5, 22:25, 23:2, 23:7, 24:12, 24:14); "life" when mortal danger is in view.
- גֹּאֵל (23:11): rendered "Redeemer" rather than "kinsman-redeemer" — the legal
  institution is noted in the commentary but the shorter form carries in the MKT.
- אֶמֶת (22:21; 23:23): "truth" understood as reliability/stability (Heb. root ʾmn),
  not an abstract propositional category.
- שֵׁם (22:1): "name" = social reputation, not a mere label; the contrast with wealth
  makes the moral claim explicit in Hebrew before any translation.
- גְּבוּל עוֹלָם (22:28; 23:10): "ancient boundary stone" — עוֹלָם marks the horizon
  of memory (from time immemorial), not literally eternal; ancient custom as sacred.
- חֵן (22:1, 22:11): "favor" when relational toward humans; "gracious" when
  describing speech quality. Both carry the aesthetic-ethical overlap of the root.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PROVERBS = {
  "22": {
    "1": '<p><strong>שֵׁם טוֹב</strong> (<em>šēm ṭôb</em>, a good name) opens the verse with the word <em>šēm</em> — name as social reputation, the legacy of one\'s character in community memory. The Hebrew verb <strong>בָּחַר</strong> (<em>bāḥar</em>, to choose, to prefer) carries the sense of deliberate selection after evaluation; one must actively cultivate reputation rather than assume wealth will suffice. <strong>חֵן</strong> (<em>ḥēn</em>, favor, graciousness) — the same root that gives us the name Hanan — denotes both inner quality and the goodwill it generates in others. The parallelism equates name with favor: both are intangible social goods that outlast coined wealth.</p>',
    "2": '<p><strong>עָשִׁיר וָרָשׁ נִפְגָּשׁוּ</strong> (rich and poor meet together) — <strong>פָּגַשׁ</strong> (<em>pāgaš</em>) is often used of unexpected or fateful meetings; here it frames the encounter of economic opposites not as accident but as creaturely fact. <strong>עֹשֵׂה כֻּלָּם יהוה</strong> (the LORD is maker of all of them) — the divine name anchors the proverb\'s ethics: the creator-creature relation is identical for rich and poor, making class-based contempt a form of insult toward the Maker (cf. 17:5). The phrase resists both servile deference to wealth and envious resentment of it.</p>',
    "3": '<p><strong>עָרוּם</strong> (<em>ʿārûm</em>, prudent, shrewd) — the same root as the serpent\'s cunning in Gen 3:1, but here rehabilitated as the positive capacity for foresight. The prudent person <strong>רָאָה רָעָה</strong> (sees danger/evil) and <strong>נִסְתָּר</strong> (hides, takes cover) — the verb <em>sātar</em> appears in texts of divine shelter (Ps 27:5). The naive (<strong>פְּתָאִים</strong>, <em>pəṯāʾîm</em>) pass on and suffer — <strong>עָנְשׁוּ</strong> from <em>ʿānaš</em>, to be fined, punished, literally to bear the consequence. The proverb teaches anticipatory prudence as a form of wisdom.</p>',
    "4": '<p><strong>עֵקֶב עֲנָוָה יִרְאַת יהוה</strong> — <strong>עֵקֶב</strong> (<em>ʿēqeb</em>, the heel, consequence, result) links humility and fear of the LORD as a compound condition yielding threefold reward: <strong>עֹשֶׁר וְכָבוֹד וְחַיִּים</strong> (riches, honor, and life). <strong>עֲנָוָה</strong> (<em>ʿanāwâ</em>, humility, meekness) is the inward posture; <strong>יִרְאַת יהוה</strong> (fear of the LORD) is its vertical dimension. Together they constitute the disposition that opens the person to receive what God gives freely — the triad of goods is a gift to the humble, not a market transaction.</p>',
    "5": '<p><strong>צִנִּים פַּחִים</strong> (thorns and snares) — a paired image of traveler hazards; both hide in the path and catch the unwary. <strong>בְּדֶרֶךְ עִקֵּשׁ</strong> (in the path of the perverse) — <strong>עִקֵּשׁ</strong> (<em>ʿiqqēš</em>, twisted, perverted) modifies "path" (<em>derek</em>) as a route that curves away from straight walking. <strong>שֹׁמֵר נַפְשׁוֹ יִרְחַק מֵהֶם</strong> (whoever guards his <em>nephesh</em>/life will stay far from them) — here <em>nephesh</em> means the whole person in mortal terms (cf. 16:17); guarding one\'s life means avoiding the moral-physical terrain of the perverse.</p>',
    "6": '<p><strong>חֲנֹךְ לַנַּעַר עַל-פִּי דַרְכּוֹ</strong> (train/dedicate a child according to his way) — <strong>חָנַךְ</strong> (<em>ḥānak</em>, to dedicate, initiate) is used of dedication of buildings (Deut 20:5) and here of childhood formation. <strong>עַל-פִּי דַרְכּוֹ</strong> (according to his way) is debated: does it mean the right way for him (his particular disposition), or simply the right path? Both senses yield the same pedagogical principle: formation must engage the actual child, not an abstraction. The promise — <strong>גַּם כִּי-יַזְקִין לֹא-יָסוּר מִמֶּנָּה</strong> — invokes lifelong formation: even when old he will not depart from it.</p>',
    "7": '<p><strong>עָשִׁיר בְּרָשִׁים יִמְשׁוֹל</strong> (the rich rules over the poor) — <strong>מָשַׁל</strong> (<em>māšal</em>, to rule, have dominion) is the same verb used of God\'s intended human dominion (Gen 1:28); here it describes the economic power differential that inverts created dignity. <strong>עֶבֶד לֹוֶה לְאִישׁ מַלְוֶה</strong> (the borrower is slave to the lender) — <strong>עֶבֶד</strong> (<em>ʿebed</em>, slave/servant) states the social consequence baldly. The proverb is descriptive, not prescriptive; it maps the real power dynamics of debt culture as a warning, not an endorsement.</p>',
    "8": '<p><strong>זֹרֵעַ עַוְלָה יִקְצָר-אָוֶן</strong> (whoever sows injustice will reap trouble/evil) — <strong>עַוְלָה</strong> (<em>ʿawlâ</em>, injustice, wrongdoing) and <strong>אָוֶן</strong> (<em>ʾāwen</em>, trouble, wickedness, futility) form a sowing-reaping moral sequence. The metaphor is agricultural and eschatological: the harvest matches the seed. <strong>וְשֵׁבֶט עֶבְרָתוֹ יִכְלֶה</strong> (the rod/weapon of his rage will end/be broken) — <strong>שֵׁבֶט</strong> (<em>šēbeṭ</em>, rod, scepter, tribe) here means the instrument of violent authority; <strong>עֶבְרָה</strong> (<em>ʿebrâ</em>, fury, overflowing wrath) names the driving emotion. The instrument of injustice fails its wielder.</p>',
    "9": '<p><strong>טוֹב-עַיִן הוּא יְבֹרָךְ</strong> (a good-eyed person — he will be blessed) — <strong>טוֹב עַיִן</strong> (good eye) is the Hebrew idiom for generosity, the opposite of the stingy <strong>רַע עַיִן</strong> (evil eye; cf. 23:6, 28:22). The eye as indicator of character runs throughout the ancient Near East; generosity begins in vision — in seeing the poor as a neighbor worthy of one\'s bread. <strong>כִּי-נָתַן מִלַּחְמוֹ לַדָּל</strong> (for he gives of his bread to the poor) — the act is voluntary sharing from one\'s own sustenance, not surplus-disposal.</p>',
    "10": '<p><strong>גָּרֵשׁ לֵץ</strong> (drive out the mocker) — <strong>לֵץ</strong> (<em>lēṣ</em>, scoffer, mocker) is the figure who mocks wisdom\'s claim on him; removing him from the community eliminates the contagion of cynicism. The verse lists three social goods that depart with him: <strong>מָדוֹן</strong> (strife, contention), <strong>רִיב</strong> (quarreling, dispute), and <strong>קָלוֹן</strong> (dishonor, shame). The proverb identifies the scoffer as the social node that generates dysfunction — his presence is architecturally corrosive.</p>',
    "11": '<p><strong>אֹהֵב טָהֳרַת-לֵב</strong> (whoever loves purity of heart) — <strong>טָהֳרַת</strong> (<em>ṭohŏrat</em>, purity, cleanness) is a cultic term applied here to the inner life (<em>lēb</em>, heart); moral purity extends from the sanctuary vocabulary to personal character. <strong>חֵן שְׂפָתָיו</strong> (grace/favor of his lips) — <strong>חֵן</strong> (<em>ḥēn</em>) here describes speech quality; the gracious speaker whose words carry aesthetic-moral weight. <strong>רֵעֵהוּ מֶלֶךְ</strong> (the king is his friend/companion) — the one who combines inner purity with gracious speech finds royal companionship; virtue is the true pathway to honor.</p>',
    "12": '<p><strong>עֵינֵי יהוה נָצְרוּ דָעַת</strong> (the eyes of the LORD watch over/preserve knowledge) — <strong>נָצַר</strong> (<em>nāṣar</em>, to keep, guard, watch over) is used of God guarding his people (Ps 31:24) and here of his attentive preservation of knowledge itself. The divine surveillance is protective toward wisdom and destructive toward its opposite: <strong>וַיְסַלֵּף דִּבְרֵי בֹגֵד</strong> (he overturns the words of the treacherous) — <strong>סָלַף</strong> (<em>sālap̄</em>, to twist, distort, overthrow) here means God actively subverts the treacherous person\'s words, making them ineffective.</p>',
    "13": '<p><strong>אָמַר עָצֵל אֲרִי בַחוּץ</strong> (the sluggard says, "A lion is outside!") — the speech-act form (<strong>אָמַר</strong>, he says) highlights the absurdity: the sluggard\'s excuse is grotesque in its implausibility. <strong>אֲרִי בַחוּץ</strong> (a lion outside) — lions were real enough dangers, but invoking one to avoid leaving the house is comic self-deception. <strong>בְּתוֹךְ רְחֹבוֹת אֵרָצֵחַ</strong> (in the middle of the streets I will be killed) — the escalation from lion outside to murder in the streets shows the sluggard\'s imagination enlarging obstacles to match his will to avoid effort.</p>',
    "14": '<p><strong>שׁוּחָה עֲמֻקָּה פִּי זָרוֹת</strong> (a deep pit is the mouth of foreign/adulterous women) — <strong>שׁוּחָה</strong> (<em>šûḥâ</em>, pit, cistern) echoes the "stranger" woman passages of chapters 1–9 where she lures the simple to Sheol. <strong>זָרוֹת</strong> (<em>zārôt</em>, strange/foreign women, adulterous women) carries both ethnic and moral connotation — those outside covenant loyalty. <strong>זְעוּם יהוה יִפָּל-שָׁם</strong> (one under the LORD\'s wrath will fall there) — the one who falls into this pit is not merely unwise but <strong>זָעַם</strong> (<em>zāʿam</em>, under divine displeasure); the seduction is the outworking of judgment.</p>',
    "15": '<p><strong>אִוֶּלֶת קְשׁוּרָה בְלֶב-נָעַר</strong> (foolishness is bound up in the heart of a child) — <strong>קָשַׁר</strong> (<em>qāšar</em>, to bind, tie) implies deep attachment; <em>ʾiwwelet</em> (foolishness) is not superficial but structurally embedded in the young person\'s <em>lēb</em>. The word for child — <strong>נָעַר</strong> (<em>naʿar</em>) — covers a range from infant to young adult, the period of formation. <strong>שֵׁבֶט מוּסָר יַרְחִיקֶנָּה מִמֶּנּוּ</strong> (the rod of discipline will drive it far from him) — <strong>מוּסָר</strong> (<em>mûsār</em>) is the disciplinary instruction that shapes character; the rod is not mere punishment but the physical enactment of formative correction.</p>',
    "16": '<p><strong>עֹשֵׁק דָּל לְהַרְבּוֹת לוֹ</strong> (oppressing the poor to increase for himself) — the infinitive <strong>לְהַרְבּוֹת</strong> marks the oppressor\'s motive: personal enrichment through exploitation. <strong>נֹתֵן לְעָשִׁיר אַךְ-לְמַחְסוֹר</strong> (giving to the rich — only to poverty) — both strategies are self-defeating. Giving gifts to the wealthy (to curry favor) and exploiting the poor (to build capital) both lead to <strong>מַחְסוֹר</strong> (<em>maḥsôr</em>, lack, poverty). The proverb inverts economic logic: the path of exploitation ends in the very deficit it sought to avoid.</p>',
    "17": '<p><strong>הַט אָזְנְךָ וּשְׁמַע דִּבְרֵי חֲכָמִים</strong> (incline your ear and hear the words of the wise) — v. 17 marks the opening of the "Words of the Wise" collection (22:17–24:22), an anthology with documented verbal parallels to the Egyptian <em>Instruction of Amenemope</em> (c. 1200 BCE). The address form shifts from third-person proverb to direct second-person instruction. <strong>הַט</strong> (<em>haṭ</em>, incline, bow) — the posture of attentive reception; the ear must lean toward wisdom. <strong>וְלִבְּךָ תָּשִׁית לְדַעְתִּי</strong> (and set your heart on my knowledge) — both ear and <em>lēb</em> (heart) are engaged: auditory reception leads to internalized knowledge.</p>',
    "18": '<p><strong>כִּי-נָעִים כִּי-תִשְׁמְרֵם בְּבִטְנֶךָ</strong> (for it is good/pleasant that you keep them in your belly/inmost self) — <strong>בֶּטֶן</strong> (<em>beṭen</em>, belly, womb, inward parts) is used metonymically for the deepest interior; wisdom is not a surface coating but lodged in the vital center of the person. <strong>יִכֹּנוּ יַחְדָּו עַל-שְׂפָתֶיךָ</strong> (that they be established together on your lips) — <em>kôn</em> (to be established, fixed, ready) implies that when wisdom is internalized, speech becomes reliable, the inner disposition expressing through the outer word.</p>',
    "19": '<p><strong>לִהְיוֹת בַּיהוה בִּטְחֶךָ</strong> (that your trust may be in the LORD) — <strong>בָּטַח</strong> (<em>bāṭaḥ</em>, to trust, have confidence) is the relational posture that Proverbs consistently cultivates; wisdom instruction ultimately aims not at self-reliance but at anchored trust in YHWH. The teacher addresses the student directly: <strong>הוֹדַעְתִּיךָ הַיּוֹם אַף-אָתָּה</strong> (I have taught you today — even you) — the emphatic <em>ʾattā</em> (you) makes the instruction pointedly personal. Teaching is address, not lecture to an abstraction.</p>',
    "20": '<p><strong>הֲלֹא כָתַבְתִּי לְךָ שָׁלִישִׁים</strong> — <strong>שָׁלִישִׁים</strong> is the crux of this verse; the word can mean "thirty" (pointing to the Amenemope parallel\'s thirty chapters), "excellent/superior things," or "officers/captains." Most scholars follow the LXX and the Amenemope connection reading "thirty sayings." The question form (<strong>הֲלֹא</strong>, "have I not?") implies the student already knows this written collection; the teacher appeals to a documented body of instruction. <strong>בְּמוֹעֵצֹת וָדָעַת</strong> (of counsel and knowledge) — the collection\'s content is characterized by wisdom\'s two governing gifts.</p>',
    "21": '<p><strong>לְהוֹדִיעֲךָ קֹשְׁטְ אִמְרֵי אֱמֶת</strong> (to make you know the reliability of words of truth) — <strong>קֹשֶׁט</strong> (<em>qōšeṭ</em>, truth, reliability) is a rare synonym for <em>ʾĕmet</em>; both carry the root meaning of stability and trustworthiness rather than abstract propositional truth. <strong>אִמְרֵי אֱמֶת</strong> (words of truth) — the teaching aims to establish the student as a reliable transmitter of stable words. <strong>לְהָשִׁיב אֲמָרִים אֱמֶת</strong> (to give back/return true words) — the purpose clause shows the social function: the student is formed to speak reliably to those who sent him, as an accurate messenger.</p>',
    "22": '<p><strong>אַל-תִּגְזָל-דָּל כִּי דַל-הוּא</strong> (do not rob the poor because he is poor) — the kî (because) clause makes the prohibition\'s rationale the very poverty of the victim; exploitation of weakness is the specific wrong named. <strong>וְאַל-תְּדַכֵּא עָנִי בַשָּׁעַר</strong> (and do not crush the afflicted at the gate) — <strong>שַׁעַר</strong> (<em>šaʿar</em>, gate) is the civic court of ancient Israel (Ruth 4:1–2; Amos 5:12); <strong>דָּכָא</strong> (<em>dākāʾ</em>, to crush, shatter) is a violent word for legal and economic oppression within the very institution meant to protect the poor.</p>',
    "23": '<p><strong>כִּי-יהוה יָרִיב רִיבָם</strong> (for the LORD will plead their case) — <strong>רִיב</strong> (<em>rîb</em>, legal dispute, lawsuit) as both noun and verb: YHWH becomes the legal advocate (<em>rib</em>) for those whose <em>rib</em> (case) has been stolen in court. <strong>וְקָבַע אֶת-קֹבְעֵיהֶם נֶפֶשׁ</strong> (and will plunder the soul/life of those who plundered them) — <strong>קָבַע</strong> (<em>qābaʿ</em>, to rob, defraud) appears in Mal 3:8 of robbing God; here it turns back on the oppressor. <strong>נֶפֶשׁ</strong> here = life; the divine plaintiff pursues the case to lethal consequence for the oppressor.</p>',
    "24": '<p><strong>אַל-תִּתְרַע אֶת-בַּעַל אָף</strong> (do not be friends with one who is a master of anger) — <strong>בַּעַל אָף</strong> (master/lord of anger) uses <em>baʿal</em> as a term of possession: the angry man is owned by his anger. <strong>וְאֶת-אִישׁ חֵמוֹת לֹא תָבוֹא</strong> (with a man of hot passions do not associate/enter) — <strong>חֵמוֹת</strong> (<em>ḥēmôt</em>, burning wrath, hot passions) pairs with <em>ʾap̄</em> (anger, nostrils); both images are thermological — uncontrolled anger as dangerous heat. The warning is social epidemiology: hot anger is contagious.</p>',
    "25": '<p><strong>פֶּן-תֵּאֱלַף אֹרְחֹתָיו</strong> (lest you learn his paths/ways) — <strong>אָלַף</strong> (<em>ʾālap̄</em>, to learn, become familiar with) is the negative counterpart of wisdom\'s instruction; proximity to the angry man is an apprenticeship in anger. <strong>וְלָקַחְתָּ מוֹקֵשׁ לְנַפְשֶׁךָ</strong> (and you take/get a snare for your soul) — <strong>מוֹקֵשׁ</strong> (<em>môqēš</em>, snare, trap) is the trap set by the wise for game (cf. Eccl 9:12); here the student sets it for himself through bad association. <em>nephesh</em> here = the self, the whole inner person who becomes ensnared.</p>',
    "26": '<p><strong>אַל-תְּהִי בְתֹקְעֵי-כָף</strong> (do not be among those who clap/strike the palm) — <strong>תָּקַע</strong> (<em>tāqaʿ</em>, to thrust, strike, blow a trumpet) in this idiom refers to the handshake pledge — a binding gesture in ancient Near Eastern commercial law. <strong>בַּעֹרְבִים מַשָּׁאוֹת</strong> (among those who pledge/give surety for loans) — <strong>עָרַב</strong> (<em>ʿārab</em>, to become surety, guarantee) and <strong>מַשָּׁאוֹת</strong> (<em>maśśāʾôt</em>, loans, burdens) together describe financial co-signing; the warning against surety runs throughout Proverbs (6:1–5; 11:15; 17:18).</p>',
    "27": '<p><strong>אִם-אֵין לְךָ לְשַׁלֵּם</strong> (if you have nothing to pay) — the conditional sets up the economic logic: the guarantor with no assets is the most exposed position. <strong>לָמָּה יִקַּח מִשְׁכָּבְךָ מִתַּחְתֶּיךָ</strong> (why should he take your bed from under you?) — <strong>מִשְׁכָּב</strong> (<em>miškāb</em>, bed, place of lying) is the last possession of the destitute; the rhetorical question (<em>lāmmāh</em>, why?) makes the outcome seem self-inflicted. The surety arrangement robs the guarantor of sleep — metaphorically and literally.</p>',
    "28": '<p><strong>אַל-תַּסֵּג גְּבוּל עוֹלָם</strong> (do not move the ancient boundary) — <strong>נָסַג</strong> (<em>nāsag</em>, to move back, remove) with <strong>גְּבוּל</strong> (<em>gəbûl</em>, border, boundary) is the act of land theft through marker-shifting (cf. Deut 19:14; 27:17). <strong>עוֹלָם</strong> (<em>ʿôlām</em>, ancient, of old, the distant past) — not "eternal" here but "from time immemorial"; ancestral arrangements carry quasi-sacred authority because they encode community memory and God-given inheritance. <strong>אֲשֶׁר עָשׂוּ אֲבוֹתֶיךָ</strong> (which your ancestors set up) — the chain of generations legitimates the marker.</p>',
    "29": '<p><strong>חָזִיתָ אִישׁ מָהִיר בִּמְלַאכְתּוֹ</strong> (you have seen a man skilled/swift in his work) — <strong>מָהִיר</strong> (<em>māhîr</em>, quick, skilled, diligent) combines speed and competence; the one who masters his craft moves with ease in it. The verse closes the chapter with a social-ascent promise: <strong>לִפְנֵי-מְלָכִים יִתְיַצָּב</strong> (before kings he will stand/present himself) — <strong>יָצַב</strong> (<em>yāṣab</em>, to stand, take position) before a king implies access to royal presence (cf. Gen 41:46 of Joseph). <strong>בַּל-יִתְיַצַּב לִפְנֵי-חֲשֻׁכִּים</strong> (he will not stand before obscure people) — <em>ḥašukkîm</em> means the dark, the obscure, those of no social standing; excellence opens royal doors.</p>'
  },
  "23": {
    "1": '<p><strong>כִּי-תֵשֵׁב לִלְחוֹם אֶת-מוֹשֵׁל</strong> (when you sit down to eat with a ruler) — <strong>מוֹשֵׁל</strong> (<em>môšēl</em>, ruler, one who exercises authority) is the powerful host; <strong>בִּין תָּבִין</strong> (you will certainly understand/consider carefully) — the infinitive absolute with the imperfect for emphasis: understanding here is a command, not a suggestion. <strong>אֵת אֲשֶׁר-לְפָנֶיךָ</strong> (what is before you) — <em>pānîm</em> (face, before) is what confronts you directly; the advice is total situational awareness, not mere table manners. This opens the Thirty Sayings collection\'s first instruction on court behavior.</p>',
    "2": '<p><strong>וְשַׂמְתָּ שַׂכִּין בְּלֹעֶךָ</strong> (put a knife to your throat) — <strong>שַׂכִּין</strong> (<em>śakkîn</em>, knife) appears only here in the Hebrew Bible; the word may be a borrowing. The violence of the image is deliberately hyperbolic: self-control in the ruler\'s presence requires something approaching self-force. <strong>אִם-בַּעַל נֶפֶשׁ אָתָּה</strong> (if you are a person of appetite/<em>nephesh</em>) — <em>bʿal nephesh</em> (master/owner of appetite) is the person driven by desire; here <em>nephesh</em> = appetite, the inner craving that must be disciplined at a powerful man\'s table where gratitude and power politics complicate ordinary hunger.</p>',
    "3": '<p><strong>אַל-תִּתְאָו לְמַטְעַמֹּתָיו</strong> (do not crave his delicacies) — <strong>תָּאָה</strong> (<em>tāʾâ</em>, to long for, desire) and <strong>מַטְעַמֹּת</strong> (<em>maṭʿammôt</em>, delicacies, choice foods, literally "tastings") recall Esau\'s fatal appetite (Gen 25:29–34). <strong>וְהוּא לֶחֶם כְּזָבִים</strong> (for it is deceptive bread) — <strong>כְּזָבִים</strong> (<em>kəzābîm</em>, lies, falsehoods) applied to food; the ruler\'s hospitality may contain unspoken obligations. The bread is a lure, not a gift.</p>',
    "4": '<p><strong>אַל-תִּיגַע לְהַעֲשִׁיר</strong> (do not toil/wear yourself out to become rich) — <strong>יָגַע</strong> (<em>yāgaʿ</em>, to grow weary, to labor to exhaustion) frames the pursuit of wealth as a form of self-destruction through overwork. <strong>מִבִּינָתְךָ חֲדָל</strong> (cease from your understanding/wisdom) — the imperative <em>ḥădal</em> (desist, cease) is the call to stop; the phrase is compact: use your understanding (<em>bînâ</em>) to know when to quit the wealth-race. Wisdom here is self-regulating: it knows its own limits.</p>',
    "5": '<p><strong>הֲתָעִיף עֵינֶיךָ בּוֹ וְאֵינֶנּוּ</strong> (you make your eyes fly at it, and it is gone) — <strong>עוּף</strong> (<em>ʿûp̄</em>, to fly) is used of the eyes darting after wealth; the irony is that wealth is the one that flies. <strong>כִּי-עָשֹׂה יַעֲשֶׂה לּוֹ כְנָפַיִם</strong> (for riches make wings for themselves) — the infinitive absolute <em>ʿāśôh yaʿăśeh</em> intensifies: money emphatically makes its own wings. <strong>כְּנֶשֶׁר יָעוּף הַשָּׁמָיִם</strong> (like an eagle it flies toward the sky) — the eagle image captures both swiftness and altitude: wealth disappears beyond recovery.</p>',
    "6": '<p><strong>אַל-תִּלְחַם אֶת-לֶחֶם רַע עָיִן</strong> (do not eat the bread of an evil-eyed person) — <strong>רַע עַיִן</strong> (evil eye) is the Hebrew idiom for miserliness or stinginess (opposite of the generous "good eye," 22:9). Eating with a miser is a social trap; his hospitality is not generosity but performance. <strong>וְאַל-תִּתְאָו לְמַטְעַמֹּתָיו</strong> (do not desire his delicacies) — the repetition of <em>maṭʿammôt</em> (from v. 3) ties the instruction together: both the powerful ruler and the stingy man offer food that is not what it appears.</p>',
    "7": '<p><strong>כִּי כְמוֹ-שָׁעַר בְּנַפְשׁוֹ כֵּן-הוּא</strong> (for as he calculates in his <em>nephesh</em>/mind, so he is) — <strong>שָׁעַר</strong> (<em>šāʿar</em>, to calculate, to estimate the price) is a commercial verb; the miser is always running a ledger in his inner being. <em>nephesh</em> here = the controlling inner self, the mind that determines behavior. <strong>אֱכֹל וּשְׁתֵה יֹאמַר לָךְ</strong> (eat and drink, he says to you) — the quoted speech contrasts with what he is actually thinking; his hospitality is verbal while his heart (<em>lēb</em>) is absent: <strong>וְלִבּוֹ בַּל-עִמָּךְ</strong> (his heart is not with you).</p>',
    "8": '<p><strong>פִּתְּךָ-אָכַלְתָּ תְּקִיאֶנָּה</strong> (the bit you ate, you will vomit it up) — the physical imagery is deliberately crude: the body expels what cannot be truly received, food eaten under false pretenses that cannot be digested. <strong>וְשִׁחַתָּ דְבָרֶיךָ הַנְּעִימִים</strong> (and your pleasant words will be wasted/destroyed) — <strong>שָׁחַת</strong> (<em>šāḥat</em>, to destroy, ruin, corrupt) applied to speech; the pleasant conversation invested in the miser\'s table yields nothing. Both the food and the social capital evaporate.</p>',
    "9": '<p><strong>בְּאָזְנֵי כְסִיל אַל-תְּדַבֵּר</strong> (in the ears of a fool do not speak) — the fool (<strong>כְּסִיל</strong>, <em>kəsîl</em>) is the one constitutionally closed to correction; the image of ears emphasizes that the problem is not acoustics but reception. <strong>כִּי-יָבוּז לְשֵׂכֶל מִלֶּיךָ</strong> (for he will despise the wisdom of your words) — <strong>בּוּז</strong> (<em>bûz</em>, to despise, hold in contempt) is the response of the mocker-fool to wisdom\'s content; wisdom is wasted on the one who despises it by constitution. The proverb counsels strategic silence: wisdom conserves itself.</p>',
    "10": '<p><strong>אַל-תַּסֵּג גְּבוּל עוֹלָם</strong> (do not move the ancient boundary) — the repetition of 22:28\'s phrase in a new context is significant; here the orphan (<strong>יְתוֹמִים</strong>, <em>yətômîm</em>) is the victim. <strong>וּבִשְׂדֵי יְתוֹמִים אַל-תָּבֹא</strong> (and do not enter the fields of orphans) — <strong>בּוֹא</strong> (<em>bôʾ</em>, to enter, come into) here means illegal encroachment on property. The orphan, like the widow, is the paradigmatic vulnerable person in Israel\'s law (Exod 22:22; Deut 24:17), lacking legal advocates — which makes the following verse\'s assurance all the more powerful.</p>',
    "11": '<p><strong>כִּי-גֹאֲלָם חָזָק הוּא</strong> (for their Redeemer is strong) — <strong>גֹּאֵל</strong> (<em>gōʾēl</em>, redeemer, kinsman-redeemer) is the legal-familial institution of Israel: the nearest male relative who steps in to restore what a family member has lost (land, freedom, life; cf. Lev 25:25–55; Ruth 2:20). Applied to YHWH, the institution is elevated into divine advocacy: God himself is the orphan\'s kinsman-redeemer. <strong>חָזָק הוּא</strong> (he is strong) — against the exploiter who counts on the orphan\'s legal helplessness, YHWH\'s strength reverses the power calculus. <strong>יָרִיב אֶת-רִיבָם אִתָּךְ</strong> (he will plead their case against you) — the courtroom language (<em>rîb</em>) of ch. 22 recurs.</p>',
    "12": '<p><strong>הָבִיאָה לַמּוּסָר לִבֶּךָ</strong> (bring your heart to instruction) — the imperative <strong>הָבִיאָה</strong> (<em>hābîʾâ</em>, bring!) calls for an act of will: the student must direct the <em>lēb</em> toward <strong>מוּסָר</strong> (<em>mûsār</em>, discipline, instruction). This is not passive absorption but active redirection of the inner life. <strong>וְאָזְנֶיךָ לְאִמְרֵי-דָעַת</strong> (and your ears to words of knowledge) — the parallel pairs heart and ear: wisdom\'s formation works through both the volitional center and the auditory gateway, requiring the whole person.</p>',
    "13": '<p><strong>אַל-תִּמְנַע מִנַּעַר מוּסָר</strong> (do not withhold discipline from a child) — <strong>מָנַע</strong> (<em>mānaʿ</em>, to withhold, restrain) implies that withholding correction is an active choice, not mere neglect; the parent must decide to apply the rod. <strong>כִּי-תַכֶּנּוּ בַשֵּׁבֶט לֹא יָמוּת</strong> (if you strike him with the rod he will not die) — the hyperbole counters overprotective hesitation; the feared outcome (death) is precisely what the rod prevents, not causes. The proverb addresses parental anxiety about harm through correction.</p>',
    "14": '<p><strong>אַתָּה בַּשֵּׁבֶט תַּכֶּנּוּ</strong> (you will strike him with the rod) — the repetition of rod-discipline from v. 13 is emphatic; vv. 13–14 form a paired instruction reinforcing each other. <strong>וְנַפְשׁוֹ מִשְּׁאוֹל תַּצִּיל</strong> (and his <em>nephesh</em>/life you will rescue from Sheol) — <strong>שְׁאוֹל</strong> (<em>šəʾôl</em>, the realm of the dead) frames the consequence without correction as death itself. <em>nephesh</em> here = life in the mortal sense; discipline is life-saving, not life-threatening. The rod is presented as an instrument of rescue, not punishment for its own sake.</p>',
    "15": '<p><strong>בְּנִי אִם-חָכַם לִבֶּךָ</strong> (my son, if your heart is wise) — the father-son address (<strong>בְּנִי</strong>, <em>bənî</em>, my son) recurs here after the impersonal second-person instructions of the court-wisdom section; the tone becomes warmly personal. <strong>יִשְׂמַח לִבִּי גַם-אָנִי</strong> (my heart will rejoice, even I) — the emphatic <em>gam-ʾānî</em> (even I myself) expresses parental delight; wisdom in the son produces joy in the father\'s inner life. The proverb creates a moral community of gladness.</p>',
    "16": '<p><strong>וְתַעְלֹזְנָה כִלְיוֹתַי</strong> (yes, my kidneys/inmost being will rejoice) — <strong>כִּלְיָה</strong> (<em>kilyâ</em>, kidney) is used in Hebrew as the seat of the deepest emotions and moral sensitivity (cf. Ps 7:10; 16:7; 26:2); parallel to <em>lēb</em> (heart) as the center of inner life. <strong>בְּדַבֵּר שְׂפָתֶיךָ מֵישָׁרִים</strong> (when your lips speak what is right/straight things) — <strong>מֵישָׁרִים</strong> (<em>mêšārîm</em>, uprightness, right things) — plural noun of quality; the father\'s inner joy is specifically triggered by the child\'s righteous speech, the outward expression of inward wisdom.</p>',
    "17": '<p><strong>אַל-יְקַנֵּא לִבְּךָ בַּחַטָּאִים</strong> (do not let your heart envy sinners) — <strong>קָנָא</strong> (<em>qānāʾ</em>, to be jealous, to envy) in the Piel; the heart is warned against the covert attraction to the apparent success of the wicked (cf. Ps 37:1; 73:2–3). <strong>כִּי אִם-בְּיִרְאַת יהוה כָּל-הַיּוֹם</strong> (but live in the fear of the LORD all the day) — <em>kî ʾim</em> introduces the positive alternative; continuous fear-of-the-LORD (<em>kol-hayyôm</em>, all the day) is the counterweight to the momentary attraction of sinners\' prosperity.</p>',
    "18": '<p><strong>כִּי אִם-יֵשׁ אַחֲרִית</strong> (for surely there is a future/end) — <strong>אַחֲרִית</strong> (<em>ʾaḥărît</em>, latter end, outcome, future) is the wisdom term for the eschatological horizon that gives present choices their weight (cf. 23:14; 24:14, 20). The fear of YHWH has a future; envy of sinners has no future that matters. <strong>וְתִקְוָתְךָ לֹא תִכָּרֵת</strong> (and your hope will not be cut off) — <strong>תִּקְוָה</strong> (<em>tiqwâ</em>, hope, expectation, a cord — same root as Rahab\'s scarlet thread in Josh 2:18) will not be <strong>כָּרַת</strong> (<em>kārat</em>, cut off, severed). The hope is structural, not merely emotional.</p>',
    "19": '<p><strong>שְׁמַע-אַתָּה בְנִי וַחֲכָם</strong> (listen, you — my son — and be wise) — the direct pronoun <strong>אַתָּה</strong> (<em>ʾattā</em>) is emphatic: this instruction is personally directed, not general. The father calls the son to two acts simultaneously: <strong>שְׁמַע</strong> (hear, attend) and <strong>חֲכַם</strong> (be wise, become wise) — hearing is not enough without wisdom\'s transformation. <strong>וְאַשֵּׁר בַּדֶּרֶךְ לִבֶּךָ</strong> (and keep/direct your heart on the path) — <strong>אָשַׁר</strong> (<em>ʾāšar</em>, to go straight, to lead straight) in the Piel; the heart must be actively directed rather than allowed to drift.</p>',
    "20": '<p><strong>אַל-תְּהִי בְסֹבְאֵי-יַיִן</strong> (do not be among those who drink wine to excess) — <strong>סָבָא</strong> (<em>sābāʾ</em>, to drink heavily, to be a winebibber) — the participial form marks a habitual lifestyle, not an occasional indulgence. <strong>בְּזֹלְלֵי בָשָׂר לָמוֹ</strong> (among those who gorge themselves on meat) — <strong>זָלַל</strong> (<em>zālal</em>, to be light, worthless, to squander, to be a glutton) combined with <em>bāśār</em> (flesh, meat) describes the excessive consumption associated with feasting. The warning pairs wine-excess with meat-excess as twin paths to self-destruction (cf. Deut 21:20 for the "stubborn and rebellious son" charge).</p>',
    "21": '<p><strong>כִּי-סֹבֵא וְזֹלֵל יִוָּרֵשׁ</strong> (for the drunkard and the glutton will come to poverty) — <strong>יִוָּרֵשׁ</strong> (<em>yiwwārēš</em>, Niphal of <em>yārash</em>, to be dispossessed, brought to poverty) — the passive of dispossession; the glutton is robbed of his own substance by his appetites. <strong>וּקְרָעִים תַּלְבִּישׁ נוּמָה</strong> (and drowsiness will clothe them in rags) — <strong>קְרָעִים</strong> (<em>qərāʿîm</em>, torn garments, rags) as the clothing of poverty; <strong>נוּמָה</strong> (<em>nûmâ</em>, drowsiness, slumber) personified as the one who clothes the idle in poverty\'s uniform. Sleep and drink conspire against the person.</p>',
    "22": '<p><strong>שְׁמַע לְאָבִיךָ זֶה יְלָדֶךָ</strong> (listen to your father, this one who gave you life) — <strong>יָלַד</strong> (<em>yālad</em>, to beget, give birth) emphasizes the father as life-giver; the relative clause <em>zeh yəlādekā</em> (this one who begot you) grounds the command in creaturely origin. <strong>וְאַל-תָּבוּז לְאִמֶּךָ כִּי זָקֵנָה</strong> (and do not despise your mother when she grows old) — <strong>בּוּז</strong> (<em>bûz</em>, to despise, treat with contempt) is what one might do to the no-longer-powerful elder; the proverb names this tendency and forbids it. Age does not diminish the honor due to parents.</p>',
    "23": '<p><strong>אֱמֶת קְנֵה וְאַל-תִּמְכֹּר</strong> (buy truth and do not sell it) — <strong>קָנָה</strong> (<em>qānâ</em>, to buy, acquire) — the commercial metaphor treats truth as a precious commodity worth market-price acquisition. <strong>אֶמֶת</strong> (<em>ʾĕmet</em>) has its root in the stability of something reliable, trustworthy, and enduring — not merely factual accuracy but ontological solidity. <strong>חׇכְמָה מוּסָר וּבִינָה</strong> (wisdom, instruction/discipline, and understanding) — the three cognitive-formational gifts of wisdom literature are listed as what one buys along with truth; they are not separate items but facets of truth\'s purchase price and yield.</p>',
    "24": '<p><strong>גּוֹל יָגִיל אֲבִי צַדִּיק</strong> (greatly rejoice will the father of a righteous one) — <strong>גּוּל</strong> (<em>gûl</em>, to rejoice, exult) with the infinitive absolute <em>gôl</em> for emphasis; the father\'s joy is emphatic and complete. <strong>וְיוֹלֵד חָכָם וְיִשְׂמַח-בוֹ</strong> (the one who begets a wise son will rejoice in him) — wisdom in a child produces joy; the parent-child bond is the social site of wisdom\'s transmission and confirmation. The verse is the positive counterpart to the shame that a foolish son brings (10:1; 17:21).</p>',
    "25": '<p><strong>יִשְׂמַח-אָבִיךָ וְאִמֶּךָ</strong> (let your father and mother be glad) — the imperative is addressed to the son: make them glad through your wisdom. <strong>וְתָגֵל יוֹלַדְתֶּךָ</strong> (let her who bore you rejoice) — <strong>יָלַד</strong> returns; <em>yôladtekā</em> (the one who bore you) is an intimate designation for the mother. The father\'s joy is in the son\'s righteous character (v. 24); the mother\'s joy is expressed here through the birthing relationship — you came from her, return her investment with wisdom.</p>',
    "26": '<p><strong>תְּנָה-לִי לִבְּךָ בְּנִי</strong> (give me your heart, my son) — <strong>נָתַן</strong> (<em>nātan</em>, to give) applied to the <em>lēb</em> (heart): the father asks for the son\'s volitional center, not mere compliance. This is the deepest request of wisdom instruction — not behavioral conformity but inner orientation toward the teacher\'s wisdom. <strong>וְעֵינֶיךָ דְּרָכַי תִּרְצֶינָה</strong> (and let your eyes keep watch over my ways) — <strong>רָצָה</strong> (<em>rāṣâ</em>, to be pleased with, delight in, approve) here means more than passive observation; the son is to find delight in the teacher\'s path, aligning vision with value.</p>',
    "27": '<p><strong>כִּי-שׁוּחָה עֲמֻקָּה זוֹנָה</strong> (for a prostitute is a deep pit) — <strong>שׁוּחָה</strong> (<em>šûḥâ</em>, pit, deep trench) recalls 22:14\'s identical image for the adulterous woman\'s mouth; here the whole person of the <strong>זוֹנָה</strong> (<em>zônâ</em>, prostitute) is the pit. <strong>וּבְאֵר צָרָה נָכְרִיָּה</strong> (and the foreign/strange woman is a narrow well) — <em>nākriyyâ</em> (foreign, strange woman) is the moral outsider; <strong>בְּאֵר צָרָה</strong> (a narrow/constricted well) suggests a place that traps those who descend. Both images are spatial — downward movement, constriction, death.</p>',
    "28": '<p><strong>אַף-הִיא כְּחֶתֶף תֶּאֱרֹב</strong> (indeed she lies in wait like a hunter/robber) — <strong>חֶתֶף</strong> (<em>ḥetep̄</em>, one who snatches, a robber) suggests predatory ambush; <strong>אָרַב</strong> (<em>ʾārab</em>, to lie in wait, to ambush) is the vocabulary of military ambush applied to seduction. <strong>וּבוֹגְדִים בְּאָדָם תּוֹסִף</strong> (and she increases the faithless/treacherous among men) — <strong>בָּגַד</strong> (<em>bāgad</em>, to deal treacherously, to be faithless) is covenant-betrayal language; she multiplies those who betray their covenantal commitments, turning men into oath-breakers.</p>',
    "29": '<p><strong>לְמִי אוֹי לְמִי אֲבוֹי</strong> (who has woe, who has sorrow) — the catalogue of <em>lemi</em> (who has) questions is a rhetorical device listing the symptoms of wine\'s destruction: <strong>אוֹי</strong> (woe), <strong>אֲבוֹי</strong> (alas, lamentation), <strong>מִדְיָנִים</strong> (strife/quarreling), <strong>שִׂיחַ</strong> (complaining, anguish), <strong>פְּצָעִים חִנָּם</strong> (wounds without cause), <strong>חַכְלִילוּת עֵינַיִם</strong> (bleary/redness of eyes). The list is accumulative and clinical — a medical-social inventory of alcohol\'s consequences before the answer is given in v. 30.</p>',
    "30": '<p><strong>לַמְאַחֲרִים עַל-הַיַּיִן</strong> (those who linger over wine) — <strong>אָחַר</strong> (<em>ʾāḥar</em>, to delay, tarry, be late) applied to sitting with wine: the damage is not in a single cup but in extended lingering. <strong>לַבָּאִים לַחְקֹר מִמְסָךְ</strong> (those who come to investigate/seek out mixed wine) — <strong>מִמְסָךְ</strong> (<em>mimsāk</em>, spiced/mixed wine) is wine blended with spices for stronger effect. The one who searches out the strongest mixture is the answer to v. 29\'s catalogue: the wine-obsessed is the source of all those symptoms.</p>',
    "31": '<p><strong>אַל-תֵּרֶא יַיִן כִּי יִתְאַדָּם</strong> (do not look at wine when it turns red) — <strong>אָדַם</strong> (<em>ʾādam</em>, to be red) — wine\'s redness is its visual seductiveness; the prohibition begins with the gaze. <strong>כִּי-יִתֵּן בַּכּוֹס עֵינוֹ</strong> (when it gives its eye in the cup) — the wine is personified: it sparkles (<em>ʿênô</em>, its eye) in the cup, looking back at the drinker. <strong>יִתְהַלֵּךְ בְּמֵישָׁרִים</strong> (it goes down smoothly) — <em>mêšārîm</em> (uprightness, straight things) used ironically: what goes down straight destroys the person who swallows it straight.</p>',
    "32": '<p><strong>אַחֲרִיתוֹ כְּנָחָשׁ יִשָּׁךְ</strong> (in the end it bites like a serpent) — <strong>אַחֲרִית</strong> (<em>ʾaḥărît</em>, the latter end, the outcome) — the wisdom term for eschatological consequence; wine\'s end is serpent-like. <strong>וּכְצִפְעֹנִי יַפְרִשׁ</strong> (and like a viper it spreads/strikes) — <strong>צִפְעֹנִי</strong> (<em>ṣipʿônî</em>, viper, adder) is a particularly dangerous snake; <strong>פָּרַשׁ</strong> (<em>pāraš</em>, to spread, to sting) suggests the poison dispersing through the body. The wine that looked like pleasure delivers venom as its true nature.</p>',
    "33": '<p><strong>עֵינֶיךָ יִרְאוּ זָרוֹת</strong> (your eyes will see strange/foreign things) — <strong>זָרוֹת</strong> (<em>zārôt</em>, strange, foreign things) — hallucinations; the same word as the "strange woman" of the sexual danger passages; wine produces the same distorted perception. <strong>וְלִבְּךָ יְדַבֵּר תַּהְפֻּכוֹת</strong> (and your heart will speak perverse things) — <strong>תַּהְפֻּכוֹת</strong> (<em>tahpukôt</em>, perverse, twisted things; from <em>hāp̄ak</em>, to overturn) are what the intoxicated heart produces: speech that inverts right and wrong, wisdom and folly.</p>',
    "34": '<p><strong>וְהָיִיתָ כְּשֹׁכֵב בְּלֶב-יָם</strong> (you will be like one lying down in the heart of the sea) — <strong>לֵב-יָם</strong> (heart of the sea) — the most dangerous place, exposed to all swells, with no stable ground; the drunk person has lost all orientation. <strong>וּכְשֹׁכֵב בְּרֹאשׁ חִבֵּל</strong> (like one lying on the top of a mast) — <strong>חִבֵּל</strong> (<em>ḥibbēl</em>, mast, rope?) — lying atop the ship\'s highest point in a storm is suicidal carelessness. Both images convey the drunk person\'s total loss of self-preservation instinct.</p>',
    "35": '<p><strong>הִכּוּנִי בַל-חָלִיתִי</strong> ("they beat me but I felt no pain") — the drunkard speaks in first person for the first time; the quoted speech is darkly comic. The perfect verbs describe past beating (<strong>הִכּוּנִי</strong>) and insensibility (<strong>חָלִיתִי</strong> from <em>ḥālâ</em>, to be sick, to feel pain). <strong>מָתַי אָקִיץ אֲבַקְשֶׁנּוּ עוֹד</strong> ("when will I wake up so I can seek another drink?") — the final word is the tragic punchline: the cycle of intoxication, damage, and renewed craving is complete. Wisdom\'s portrait of the drunkard ends with his own voice asking for more poison.</p>'
  },
  "24": {
    "1": '<p><strong>אַל-תְּקַנֵּא בְּאַנְשֵׁי הָרָעָה</strong> (do not envy the men of evil) — <strong>קָנָא</strong> (<em>qānāʾ</em>, to be jealous/envious) is the affective disposition that must be actively resisted; the evil man\'s visible success generates a pull on the viewer. <strong>וְאַל-תִּתְאָו לִהְיוֹת אִתָּם</strong> (and do not desire to be with them) — the second prohibition targets not just envy of their goods but desire for their company; association is itself the danger. The proverb opens chapter 24\'s first section with the foundational warning against the attraction of wickedness.</p>',
    "2": '<p><strong>כִּי-שֹׁד יֶהְגֶּה לִבָּם</strong> (for their heart meditates/murmurs destruction) — <strong>שֹׁד</strong> (<em>šôd</em>, ruin, devastation, violence) is what the wicked person\'s <em>lēb</em> (heart) continuously rehearses. <strong>הָגָה</strong> (<em>hāgâ</em>, to murmur, meditate, utter) is the same verb used of the righteous meditating on Torah (Ps 1:2); here it is applied to the wicked\'s constant rumination on harm. <strong>וְעָמָל שְׂפָתֵיהֶם תְּדַבֵּרְנָה</strong> (and their lips speak trouble/toil) — <em>ʿāmāl</em> (toil, mischief, trouble) is what their meditation produces in speech.</p>',
    "3": '<p><strong>בְּחׇכְמָה יִבָּנֶה בָּיִת</strong> (by wisdom a house is built) — <strong>בָּנָה</strong> (<em>bānâ</em>, to build) in Niphal; the house (<em>bayit</em>) is both the physical dwelling and the family dynasty. Wisdom is the structural principle of lasting household establishment. <strong>וּבִתְבוּנָה יִתְכּוֹנָן</strong> (and by understanding it is established) — <strong>תְּבוּנָה</strong> (<em>təbûnâ</em>, understanding, discernment) from <em>bîn</em>; <strong>כּוּן</strong> (<em>kôn</em>, to be established, fixed) in the Hithpael — the house establishes itself through understanding, the internalized application of wisdom to lived decisions.</p>',
    "4": '<p><strong>וּבְדַעַת חֲדָרִים יִמָּלְאוּ</strong> (and by knowledge the rooms are filled) — the house-building metaphor extends: after construction (v. 3) comes furnishing; <strong>חֲדָרִים</strong> (<em>ḥădārîm</em>, inner rooms, chambers) fill with <strong>כָּל-הוֹן יָקָר וְנָעִים</strong> (all precious and pleasant wealth). The triad of wisdom-understanding-knowledge (ḥokmâ-təbûnâ-daʿat) builds, establishes, and furnishes the house. The progression mirrors creation: God used wisdom to found the earth (3:19–20).</p>',
    "5": '<p><strong>גֶּבֶר-חָכָם בַּעוֹז</strong> (a wise man is strong/in strength) — the connection between wisdom and power runs against the intuition that physical strength is primary. <strong>גֶּבֶר</strong> (<em>geber</em>, a strong man, a warrior) qualified by <em>ḥākām</em> (wise) — wisdom is the warrior\'s true resource. <strong>וְאִישׁ-דַּעַת מְאַמֶּץ-כֹּחַ</strong> (and a man of knowledge grows in might) — <strong>אָמַץ</strong> (<em>ʾāmaṣ</em>, to be strong, to confirm, to grow mighty) in the Piel; knowledge is a power-amplifier, increasing the person\'s effective capacity beyond raw force.</p>',
    "6": '<p><strong>כִּי-בְתַחְבֻּלוֹת תַּעֲשֶׂה-לְּךָ מִלְחָמָה</strong> (for by wise guidance you make war for yourself) — <strong>תַּחְבֻּלוֹת</strong> (<em>taḥbulôt</em>, guidance, steersmanship — from <em>ḥeβel</em>, a rope/cord used in sailing) is the wisdom of strategic direction; the image is nautical before it is military. <strong>וּתְשׁוּעָה בְּרֹב יוֹעֵץ</strong> (and victory comes with many advisers) — this principle from 11:14 (with identical wording) is repeated; wisdom is distributed in community, not concentrated in one mind. The military context makes the political application concrete.</p>',
    "7": '<p><strong>רָאמוֹת לָאֱוִיל חׇכְמוֹת</strong> (wisdom is heights/coral to the fool) — <strong>רָאמוֹת</strong> (<em>rāʾmôt</em>) is debated: "heights" (inaccessible elevations) or "coral" (precious deep-sea material, equally inaccessible). Either way: wisdom is beyond the fool\'s reach — spatially unattainable. <strong>בַּשַּׁעַר לֹא יִפְתַּח-פִּיהוּ</strong> (at the gate he will not open his mouth) — the civic gate is the court of public wisdom and justice; the fool\'s silence there is the practical consequence of wisdom\'s inaccessibility to him. He has nothing to contribute to the community\'s deliberation.</p>',
    "8": '<p><strong>מְחַשֵּׁב לְהָרַע</strong> (whoever plans to do evil) — <strong>חָשַׁב</strong> (<em>ḥāšab</em>, to think, plan, reckon, devise) in the Piel; intentional, sustained scheming. <strong>בַּעַל מְזִמּוֹת יִקְרְאוּ-לוֹ</strong> (he will be called a master of schemes) — <em>bʿal məzimmôt</em> (master/owner of schemes); <strong>מְזִמָּה</strong> (<em>məzimmâ</em>) can be positive (prudent planning) or negative (evil schemes) depending on context; here unambiguously negative. The person becomes identified with his scheming — reputation as a troublemaker attaches to him publicly.</p>',
    "9": '<p><strong>זִמַּת אִוֶּלֶת חַטָּאת</strong> (the scheme/purpose of folly is sin) — <strong>זִמָּה</strong> (<em>zimmâ</em>, scheme, plan, evil device) applied to <em>ʾiwwelet</em> (folly); folly is not merely stupid but sinful in its intention. <strong>וְתוֹעֲבַת לְאָדָם לֵץ</strong> (and the mocker is an abomination to people) — <strong>תּוֹעֵבָה</strong> (<em>tôʿēbâ</em>, abomination) applied to the <em>lēṣ</em> (scoffer/mocker): what is usually a cultic category (detestable to God) is here applied to the community\'s social judgment. The mocker evokes the same moral revulsion in humans that abomination evokes in God.</p>',
    "10": '<p><strong>הִתְרַפִּיתָ בְּיוֹם צָרָה</strong> (if you falter in the day of trouble) — <strong>רָפָה</strong> (<em>rāpâ</em>, to sink, relax, go limp) in the Hithpael — letting oneself go slack; the day of <strong>צָרָה</strong> (<em>ṣārâ</em>, trouble, distress, tightness) is precisely when strength is tested. <strong>צַר כֹּחֶךָ</strong> (your strength is small) — <em>ṣar</em> (narrow, small, cramped) — strength that cannot hold under pressure was always small; adversity reveals what was there all along. The proverb challenges the person to know their real capacity before crisis arrives.</p>',
    "11": '<p><strong>הַצֵּל לְקוּחִים לַמָּוֶת</strong> (rescue those being taken to death) — <strong>לָקַח</strong> (<em>lāqaḥ</em>, to take, seize) in the Qal passive participle — those already seized and being led; the urgency is immediate. <strong>וּמוֹטִים לַהֶרֶג אִם-תַּחְשׂוֹךְ</strong> (and those stumbling toward slaughter, if you hold back) — <strong>חָשַׂךְ</strong> (<em>ḥāśak</em>, to restrain, withhold) is the sin of inaction when intervention could save life. The proverb mandates active rescue as a moral obligation, not optional generosity.</p>',
    "12": '<p><strong>כִּי-תֹאמַר הֵן לֹא-יָדַעְנוּ זֶה</strong> (if you say, "We did not know this") — the quoted speech is the self-exculpating claim of willful ignorance; the verse dismantles it by invoking divine omniscience. <strong>הֲלֹא-תֹכֵן לִבּוֹת יָבִין</strong> (does not he who weighs hearts understand?) — <strong>תָּכַן</strong> (<em>tākan</em>, to weigh, to measure precisely) applied to the <em>lēb</em> (hearts); God is the precisely calibrated scales of inner intention. <strong>וְנֹצֵר נַפְשְׁךָ הוּא יֵדָע</strong> (he who guards your <em>nephesh</em>/life — he knows) — <em>nephesh</em> here = life; the one who preserves your existence also observes your moral choices. <strong>וְהֵשִׁיב לְאָדָם כְּפָעֳלוֹ</strong> (and he will repay each person according to their deed) — the lex talionis principle at divine scale: <em>kəpāʿŏlô</em> (according to their work/deed).</p>',
    "13": '<p><strong>אֱכָל-בְּנִי דְבַשׁ כִּי-טוֹב</strong> (eat honey, my son, because it is good) — the father-son address returns; the instruction becomes inviting rather than prohibitive. <strong>דְּבַשׁ</strong> (<em>dəbaš</em>, honey) is the paradigmatic good taste (Ps 19:11; 119:103); <strong>וְנֹפֶת מָתוֹק עַל-חִכֶּךָ</strong> (and the honeycomb is sweet to your palate) — <em>nōp̄et</em> (honeycomb, dripping honey) intensifies; <em>ḥikkekā</em> (your palate/taste) is the faculty of aesthetic discrimination. The honey sets up the analogy of v. 14.</p>',
    "14": '<p><strong>כֵּן דְּעֵה חׇכְמָה לְנַפְשֶׁךָ</strong> (so know wisdom for your soul) — the comparative <em>kēn</em> (so, thus) draws the analogy: as honey is good to the taste, so wisdom is good to the <em>nephesh</em>. <em>nephesh</em> here = the inner person, the self that is nourished by wisdom as the body is nourished by honey. <strong>אִם-מָצָאתָ וְיֵשׁ אַחֲרִית</strong> (if you find it, there is a future) — <strong>אַחֲרִית</strong> (<em>ʾaḥărît</em>) recurs: the future/outcome that wisdom guarantees. <strong>וְתִקְוָתְךָ לֹא תִכָּרֵת</strong> (your hope will not be cut off) — identical to 23:18; wisdom\'s promise is structural: a future that cannot be severed.</p>',
    "15": '<p><strong>אַל-תֶּאֱרֹב רָשָׁע לִנְוֵה צַדִּיק</strong> (do not lie in wait, O wicked one, against the dwelling of the righteous) — the verse addresses the wicked man directly — a rhetorical shift to second person that implicates anyone tempted to plot against the righteous. <strong>אַל-תְּשַׁדֵּד רִבְצוֹ</strong> (do not raid his resting place) — <strong>שָׁדַד</strong> (<em>šādad</em>, to ravage, spoil, destroy) is strong violence; <em>ribṣô</em> (his resting place) is domestic peace. The instruction implies that the righteous man\'s home is under his Redeemer\'s protection (cf. 23:11).</p>',
    "16": '<p><strong>כִּי שֶׁבַע יִפּוֹל צַדִּיק וָקָם</strong> (for the righteous falls seven times and rises again) — <strong>שֶׁבַע</strong> (<em>šebaʿ</em>, seven) is the number of completeness: however many times the righteous person falls, he rises. <strong>נָפַל</strong> (fall) and <strong>קוּם</strong> (rise) are the two poles of the righteous life — not immunity from adversity but resurrection from it. <strong>וּרְשָׁעִים יִכָּשְׁלוּ בְרָעָה</strong> (but the wicked stumble in calamity) — contrast: the wicked fall when calamity comes and do not rise. The difference is not circumstance but the capacity for recovery that righteousness grants.</p>',
    "17": '<p><strong>בִּנְפֹל אוֹיִבְךָ אַל-תִּשְׂמָח</strong> (when your enemy falls do not rejoice) — <strong>שָׂמַח</strong> (<em>śāmaḥ</em>, to rejoice) is forbidden at the enemy\'s fall; the impulse is natural but the proverb confronts it directly. <strong>וּבִכָּשְׁלוֹ אַל-יָגֵל לִבֶּךָ</strong> (and when he stumbles do not let your heart exult) — <em>lēb</em> (heart) is the seat of the attitude; even private celebration is wrong. The prohibition reaches inward, not just to public behavior.</p>',
    "18": '<p><strong>פֶּן-יִרְאֶה יהוה וְרַע בְּעֵינָיו</strong> (lest the LORD see and it be evil in his eyes) — the LORD\'s gaze is the controlling concern: gloating at the enemy\'s fall is <strong>רַע בְּעֵינָיו</strong> (evil in his eyes), the standard of YHWH\'s moral evaluation. <strong>וְהֵשִׁיב מֵעָלָיו אַפּוֹ</strong> (and he turns his anger away from your enemy) — the ironic consequence: if you gloat, God redirects his anger from the enemy to you. The enemy\'s calamity is God\'s action; appropriating it as your satisfaction perverts its purpose.</p>',
    "19": '<p><strong>אַל-תִּתְחַר בַּמְּרֵעִים</strong> (do not fret/be agitated because of evildoers) — <strong>חָרָה</strong> (<em>ḥārâ</em>, to burn, to be angry, to fret) in the Hithpael; self-generating agitation at the wicked, which Ps 37:1 opens identically. <strong>אַל-תְּקַנֵּא בָּרְשָׁעִים</strong> (do not envy the wicked) — <em>qānāʾ</em> (envy, jealousy) targets their apparent prosperity. Both fretting and envying are responses to perceiving the wicked as having something worth having; the proverb cuts the perception at the root.</p>',
    "20": '<p><strong>כִּי לֹא-תִהְיֶה אַחֲרִית לָרָע</strong> (for the evil person has no future/outcome) — <strong>אַחֲרִית</strong> (<em>ʾaḥărît</em>) recurs for the third time in ch. 24 (vv. 14, 18, 20); the chapter organizes itself around the concept of future outcome. The wicked have no lasting future because their prosperity is structurally temporary. <strong>נֵר רְשָׁעִים יִדְעָךְ</strong> (the lamp of the wicked will be snuffed out) — the lamp (<em>nēr</em>) is a common image for life and household continuation (cf. 13:9; 20:20); its extinction is the end of legacy as well as life.</p>',
    "21": '<p><strong>יְרָא-אֶת-יהוה בְּנִי וָמֶלֶךְ</strong> (fear the LORD, my son, and the king) — the father-son address returns for the final instruction of the "Words of the Wise" collection. The dual command pairs YHWH and king; both represent legitimate authorities that wisdom honors. <strong>עִם-שׁוֹנִים אַל-תִּתְעָרָב</strong> (do not associate with those who seek change/are different) — <strong>שׁוֹנִים</strong> (<em>šônîm</em>) — those who are different, who rebel against established order; <strong>עָרַב</strong> (<em>ʿārab</em>, to mix, to become surety, to associate) in the Hithpael warns against social mixing with the dangerously unstable.</p>',
    "22": '<p><strong>כִּי-פִתְאֹם יָקוּם אֵידָם</strong> (for suddenly their disaster will rise) — <strong>פִּתְאֹם</strong> (<em>pitʾôm</em>, suddenly, unexpectedly) marks the characteristic swiftness of divine judgment on the rebellious; no warning, no gradual approach. <strong>וּפִיד שְׁנֵיהֶם מִי יוֹדֵעַ</strong> (and the ruin/calamity of both — who knows?) — <strong>פִּיד</strong> (<em>pîd</em>, ruin, calamity, destruction) is a rare word (cf. Job 12:5; 30:12, 24; 31:29); its scope extends to both king and rebel: both can bring sudden ruin. The uncertainty (<em>mî yôdēaʿ</em>, who knows?) underscores the unpredictability of those who hold power without wisdom.</p>',
    "23": '<p><strong>גַּם-אֵלֶּה לַחֲכָמִים</strong> (these also are for the wise) — the superscription marks the opening of a second sub-collection (24:23–34), distinct from the "Thirty Sayings" of 22:17–24:22. <strong>הַכֵּר-פָּנִים בְּמִשְׁפָּט בַּל-טוֹב</strong> (to show partiality in judgment is not good) — <strong>הַכֵּר פָּנִים</strong> (to recognize the face, to show partiality) is the idiom for favoring based on appearance or social status rather than justice. Judicial impartiality is foundational to the wisdom tradition\'s ethics (Lev 19:15; Deut 16:19).</p>',
    "24": '<p><strong>אֹמֵר לְרָשָׁע צַדִּיק אָתָּה</strong> (whoever says to the wicked, "You are righteous") — the false verdict in court; calling the guilty innocent inverts the entire judicial order. <strong>יִקְּבֻהוּ עַמִּים</strong> (peoples will curse him) — <strong>קָבַב</strong> (<em>qābab</em>, to curse, utter a curse against) — the universal social consequence: not just one wronged party but <em>ʿammîm</em> (peoples) condemn the corrupt judge. <strong>יִזְעָמוּהוּ לְאֻמִּים</strong> (nations will denounce him) — <em>lēʾummîm</em> (peoples, nations) parallel <em>ʿammîm</em>; the scope is universal: unjust acquittal of the wicked is an offense against humanity, not merely one case.</p>',
    "25": '<p><strong>וְלַמּוֹכִיחִים יִנְעָם</strong> (but those who rebuke/reprove will find delight) — <strong>יָכַח</strong> (<em>yākaḥ</em>, to rebuke, reprove, argue a case, adjudicate) in the Hiphil participle — those who exercise the prophetic-judicial function of honest reproof. <strong>עֲלֵיהֶם תָּבוֹא בִרְכַּת-טוֹב</strong> (upon them will come a blessing of good) — the passive of divine blessing (<em>tābôʾ</em>, will come) settles on those who speak truth against the wicked. The good-blessing (<em>birkat-ṭôb</em>) is the counterpart to the peoples\' curse on the corrupt judge.</p>',
    "26": '<p><strong>שְׂפָתַיִם יִשָּׁק</strong> (he will kiss the lips) — the metaphor is one of the most striking in Proverbs: an honest answer is like a kiss. <strong>מֵשִׁיב דְּבָרִים נְכֹחִים</strong> (one who gives back right/direct words) — <strong>נָכוֹחַ</strong> (<em>nākôaḥ</em>, right, straight, before one) describes speech that goes directly where it should without deflection. The kiss metaphor suggests warmth, intimacy, and trust; honest speech creates and sustains the bond that sycophancy destroys.</p>',
    "27": '<p><strong>הָכֵן בַּחוּץ מְלַאכְתֶּךָ</strong> (prepare your outdoor work) — <strong>כּוּן</strong> (<em>kôn</em>, to establish, prepare, make ready) in the Hiphil imperative; outdoor work (<em>ḥûṣ</em>, outside, field) comes first. <strong>וְאַחַר בָּנִיתָ בֵיתֶךָ</strong> (and afterward build your house) — the sequence is economic prudence: establish productive capacity before consuming it in construction. The proverb echoes Jesus\'s parable of the builder counting costs (Luke 14:28–30); wisdom calculates before committing.</p>',
    "28": '<p><strong>אַל-תִּהְיֶה עֵד-חִנָּם בְּרֵעֶךָ</strong> (do not be a witness without cause against your neighbor) — <strong>חִנָּם</strong> (<em>ḥinnām</em>, for nothing, without cause, groundlessly) modifies the witness role; groundless testimony is the legal wrong named. <strong>וַהֲפִתִּיתָ בִּשְׂפָתֶיךָ</strong> (and do not deceive with your lips) — <strong>פָּתָה</strong> (<em>pātâ</em>, to open, to deceive, to entice) — verbal deception in legal context; the prohibition extends from false testimony to any form of speech designed to mislead in matters affecting another\'s legal standing.</p>',
    "29": '<p><strong>אַל-תֹּאמַר אֶעֱשֶׂה-לוֹ כַּאֲשֶׁר עָשָׂה-לִי</strong> (do not say, "I will do to him as he did to me") — the quoted speech is the voice of human retributive instinct; the proverb forbids it by forbidding even its formulation in speech. <strong>אָשִׁיב לָאִישׁ כְּפָעֳלוֹ</strong> (I will repay the man according to his deed) — the self-assumed role of judge and avenger; <em>kəpāʿŏlô</em> (according to his deed) is exactly YHWH\'s prerogative (24:12). Taking it for oneself usurps the divine role. The New Testament\'s prohibition on revenge (Rom 12:17–19) has this exact proverb as background.</p>',
    "30": '<p><strong>עַל שְׂדֵה אִישׁ-עָצֵל עָבַרְתִּי</strong> (I passed by the field of a lazy man) — the poem shifts to autobiographical first-person narrative, the sage as observer. <strong>וְעַל-כֶּרֶם אָדָם חֲסַר-לֵב</strong> (and by the vineyard of a man who lacked heart/sense) — <strong>חֲסַר-לֵב</strong> (<em>ḥăsar-lēb</em>, lacking heart, senseless) — the <em>lēb</em> (heart/mind) is the organ of wisdom; to lack it is to be constitutionally incapable of prudent planning. The field and vineyard are read as diagnostic landscapes.</p>',
    "31": '<p><strong>וְהִנֵּה עָלָה כֻלּוֹ קִמְּשֹׂנִים</strong> (and behold, it was all overgrown with thorns) — the <em>wəhinnēh</em> (and behold) signals the vivid, surprising scene that confronts the observer. <strong>קִמָּשׂוֹן</strong> (<em>qimmāśôn</em>, weeds, nettles, thorns) — a term for invasive vegetation that colonizes untended ground. <strong>כִּסּוּ פָנָיו חֲרֻלִּים</strong> (nettles covered its face) — <em>pānāyw</em> (its face) is the surface of the field; <em>ḥarullîm</em> (nettles, weeds) have taken the face. <strong>וְגֶדֶר אֲבָנָיו נֶהֱרָסָה</strong> (and its stone wall was broken down) — the infrastructure of order (wall = property boundary + protection) has collapsed along with the crop.</p>',
    "32": '<p><strong>וָאֶחֱזֶה אָנֹכִי אָשִׁית לִבִּי</strong> (I saw it, I took it to heart) — the observer\'s response: <strong>אָשִׁית לִבִּי</strong> (I set my heart) — active attention, not passive seeing. <strong>רָאִיתִי לָקַחְתִּי מוּסָר</strong> (I looked and received instruction) — <strong>לָקַח מוּסָר</strong> (to receive/take instruction) is the phrase for wisdom\'s appropriation (cf. 1:3; 8:10); the sage reads the landscape as a moral text. The neglected field is the medium of instruction; observation becomes formation.</p>',
    "33": '<p><strong>מְעַט שֵׁנוֹת מְעַט תְּנוּמוֹת</strong> (a little sleep, a little slumber) — the triple diminutive (<strong>מְעַט</strong>, <em>məʿaṭ</em>, a little) is ironic; each "little" compounds. <strong>מְעַט חִבֻּק יָדַיִם לִשְׁכָּב</strong> (a little folding of hands to rest) — <strong>חָבַק יָדַיִם</strong> (to fold the hands) is the posture of inaction; the hands that should work are crossed in comfortable rest. Identical to 6:10, where the same picture opens the warning about the sluggard\'s self-destruction. The repetition of a known text signals that the wise man has absorbed a prior instruction and sees it confirmed in the field before him.</p>',
    "34": '<p><strong>וּבָא-מִתְהַלֵּךְ רֵישֶׁךָ</strong> (then poverty will come on you like a wanderer) — <strong>מִתְהַלֵּךְ</strong> (<em>mitəhallēk</em>, Hithpael participle of <em>hālak</em>, to walk) — poverty that walks toward you like a drifter, arriving inevitably. <strong>וּמַחְסֹרְךָ כְּאִישׁ מָגֵן</strong> (and your need like an armed man) — <em>māgēn</em> is often "shield" but here the armed defender figure suggests poverty arriving with military force, not to be denied entry. Identical to 6:11; the poem ends with the same warning with which it began in chapter 6. The sage has observed it in the world and confirms what wisdom had already taught.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'proverbs')
    merge_comm(existing, PROVERBS)
    save_comm('mkt-original', 'proverbs', existing)
    print('Proverbs 22–24 mkt-original written.')

if __name__ == '__main__':
    main()
